bool Testbed::jit_fusion() {
	bool val = true;
	bool any_on = false;
	bool any_network = false;
	for (const auto& device : m_devices) {
		if (device.network()) {
			bool device_on = device.network()->jit_fusion();
			val &= device_on;
			any_on |= device_on;
			any_network = true;
		}
	}

	if (!any_network) {
		return m_jit_fusion;
	}

	if (val != any_on) {
		set_jit_fusion(false);
	}

	m_jit_fusion = val;
	return val;
}

